import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generator'

generatorHandler({
  onManifest() {
    return {
      prettyName: 'REST API Client',
      defaultOutput: 'generated/rest-client',
    }
  },
  async onGenerate(options) {
    await generate(options)
  },
})

import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorConfig, GeneratorOptions } from '@prisma/generator-helper'

import { renderRestClient } from './template'

/**
 * Resolves the output directory from the generator config, handling env-var references
 * (e.g. `output = env("MY_OUTPUT_DIR")`).
 */
function resolveOutputDir(config: GeneratorConfig): string {
  const output = config.output
  if (!output) {
    throw new Error(
      'An output path is required for the `prisma-generator-rest-client` generator.\n' +
        'Please add `output = "./generated/rest-client"` to your generator block.',
    )
  }
  if (output.fromEnvVar !== null) {
    const envValue = process.env[output.fromEnvVar]
    if (!envValue) {
      throw new Error(
        `Environment variable '${output.fromEnvVar}' referenced in generator output is not set.`,
      )
    }
    return envValue
  }
  if (output.value === null) {
    throw new Error(
      'An output path is required for the `prisma-generator-rest-client` generator.\n' +
        'Please add `output = "./generated/rest-client"` to your generator block.',
    )
  }
  return output.value
}

/**
 * Entry point called by the generator protocol handler. Reads the DMMF from
 * `options.dmmf`, writes a single `rest-client.ts` file to the configured
 * output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options.generator)
  await fs.mkdir(outputDir, { recursive: true })

  const content = renderRestClient(options.dmmf.datamodel.models, options.dmmf.datamodel.enums)
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}
